FROM jsonb_to_recordset('[{"id": "cap-104-chinese-015", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「我的記憶運作得像一面蜘蛛網。不重要的事物，比如風，就讓它們過去；但\n捕獲的蒼蠅就懸掛在網上加以儲存，直到我那心智的蜘蛛需要時再吃掉。」這\n段文字的涵義，與下列何者最接近？", "options": ["記憶應視事物的輕重而有所擇取", "往事如風，既已逝去，就無須記憶", "記憶如獵物，運用技巧才能捕獲它", "存在腦中的記憶終將隨著時間而消散"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 15, "raw_text": "15. 「我的記憶運作得像一面蜘蛛網。不重要的事物，比如風，就讓它們過去；但\n    捕獲的蒼蠅就懸掛在網上加以儲存，直到我那心智的蜘蛛需要時再吃掉。」這\n    段文字的涵義，與下列何者最接近？\n    (A)記憶應視事物的輕重而有所擇取\n    (B)往事如風，既已逝去，就無須記憶\n    (C)記憶如獵物，運用技巧才能捕獲它\n    (D)存在腦中的記憶終將隨著時間而消散\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-016", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「盡忠益時者雖仇必賞，犯法怠慢者雖親必罰。」這句話所強調的執法原則，\n與下列何者相去最遠？", "options": ["恩必加於有功，刑必斷於有罪", "不因喜以加賞，不因怒以加罰", "勝法之務莫急於去奸，去奸之本莫深於嚴刑", "衡之於左右，繩之於內外，無私輕重是為公正"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 16, "raw_text": "16. 「盡忠益時者雖仇必賞，犯法怠慢者雖親必罰。」這句話所強調的執法原則，\n    與下列何者相去最遠？\n    (A)恩必加於有功，刑必斷於有罪\n    (B)不因喜以加賞，不因怒以加罰\n    (C)勝法之務莫急於去奸，去奸之本莫深於嚴刑\n    (D)衡之於左右，繩之於內外，無私輕重是為公正\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-017", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「細菌和殺死它們的抗生素之間的戰爭，就如同大國之間的軍備競爭，精益求\n精，更相勝出，__________。」畫線處填入下列何者最能說明上述比喻的內涵？", "options": ["數十年來，細菌在這場戰爭中逐漸占優勢，和抗生素的關係就像一個慢慢失 去平衡的蹺蹺板", "在抗生素的攻擊下，通常會有少數突變的細菌存活，它們會繁殖，同時也將 保護它們的基因傳遞下去", "面對抗生素，存活下來具抵抗力的細菌將不斷繁衍壯大；為了消滅具抵抗力 的細菌，人類又研發出更強的抗生素", "人類要研發出能對抗細菌又不會傷害人體的抗生素，非常困難。若研發失 敗，人類可能得和細菌共處一段不愉快的時間"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17. 「細菌和殺死它們的抗生素之間的戰爭，就如同大國之間的軍備競爭，精益求\n    精，更相勝出，__________。」畫線處填入下列何者最能說明上述比喻的內涵？\n    (A)數十年來，細菌在這場戰爭中逐漸占優勢，和抗生素的關係就像一個慢慢失\n       去平衡的蹺蹺板\n    (B)在抗生素的攻擊下，通常會有少數突變的細菌存活，它們會繁殖，同時也將\n       保護它們的基因傳遞下去\n    (C)面對抗生素，存活下來具抵抗力的細菌將不斷繁衍壯大；為了消滅具抵抗力\n       的細菌，人類又研發出更強的抗生素\n    (D)人類要研發出能對抗細菌又不會傷害人體的抗生素，非常困難。若研發失\n       敗，人類可能得和細菌共處一段不愉快的時間\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-018", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "袁宏道與友人書云：「人情必有所寄，然後能樂。故有以弈為寄，有以色為寄，\n有以技為寄，有以文為寄。古之達人，高人一層，只是他情有所寄，不肯浮泛\n虛度光景。」這段文字的主要涵義，與下列何者最接近？", "options": ["以物為寄應該有所節制，不可浮濫", "古之達人寄懷於民，不求一己之樂", "情感有所依託，生命方能愉悅自適", "習得多種才藝，方能晉身達人之列"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 18, "raw_text": "18. 袁宏道與友人書云：「人情必有所寄，然後能樂。故有以弈為寄，有以色為寄，\n    有以技為寄，有以文為寄。古之達人，高人一層，只是他情有所寄，不肯浮泛\n    虛度光景。」這段文字的主要涵義，與下列何者最接近？\n    (A)以物為寄應該有所節制，不可浮濫\n    (B)古之達人寄懷於民，不求一己之樂\n    (C)情感有所依託，生命方能愉悅自適\n    (D)習得多種才藝，方能晉身達人之列\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-019", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列文句，何者有語病？", "options": ["時光飛逝，故鄉的松濤只能在回憶裡澎湃", "在國中畢業前夕，我們聚在一起緬懷未來", "對許多人而言，巴黎的浪漫並非不可企及", "為了遠離塵俗，我跋山涉水來到這片山林"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 19, "raw_text": "19. 下列文句，何者有語病？\n    (A)時光飛逝，故鄉的松濤只能在回憶裡澎湃\n    (B)在國中畢業前夕，我們聚在一起緬懷未來\n    (C)對許多人而言，巴黎的浪漫並非不可企及\n    (D)為了遠離塵俗，我跋山涉水來到這片山林\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-020", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "民初某學者仍留著前朝的舊髮式，拖著一條辮子去北大授課，學生哄堂大笑，他\n說：「我的辮子一剪就沒有了，但你們心中的辮子恐怕就沒有那麼容易剪掉了。」\n他話中的涵義，與下列何者最接近？", "options": ["剃一人之髮，易；剃萬人之髮，難", "復舊時之制，易；立今世之制，難", "破山中之賊，易；破心中之賊，難", "察小人之過，易；知君子之過，難"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 20, "raw_text": "20. 民初某學者仍留著前朝的舊髮式，拖著一條辮子去北大授課，學生哄堂大笑，他\n    說：「我的辮子一剪就沒有了，但你們心中的辮子恐怕就沒有那麼容易剪掉了。」\n    他話中的涵義，與下列何者最接近？\n    (A)剃一人之髮，易；剃萬人之髮，難\n    (B)復舊時之制，易；立今世之制，難\n    (C)破山中之賊，易；破心中之賊，難\n    (D)察小人之過，易；知君子之過，難\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-021", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「如果每個人都是特別的，那就沒有一個特別；如果每個人都得到一個獎\n杯，獎杯就變得毫無意義。生活最甜美的樂趣，在於承認自己並不特別。」\n這段文字的涵義，與下列何者最接近？", "options": ["不要強調自己與眾不同", "追逐名利其實毫無意義", "認真生活才有甜美的樂趣", "生活樂在發掘他人的特別"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21. 「如果每個人都是特別的，那就沒有一個特別；如果每個人都得到一個獎\n    杯，獎杯就變得毫無意義。生活最甜美的樂趣，在於承認自己並不特別。」\n    這段文字的涵義，與下列何者最接近？\n    (A)不要強調自己與眾不同   (B)追逐名利其實毫無意義\n    (C)認真生活才有甜美的樂趣  (D)生活樂在發掘他人的特別\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-022", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列文句，何者用字完全正確？", "options": ["各種跡象一再顯示他有犯罪嫌疑", "紐約是個交通便利、人口綢密的都市", "認真負責的態度，是他履創佳績的關鍵", "你整天遊手好閒，只是突然虛度光陰罷了"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 22, "raw_text": "22. 下列文句，何者用字完全正確？\n    (A)各種跡象一再顯示他有犯罪嫌疑\n    (B)紐約是個交通便利、人口綢密的都市\n    (C)認真負責的態度，是他履創佳績的關鍵\n    (D)你整天遊手好閒，只是突然虛度光陰罷了\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-023", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「書，飢讀之以當肉；寒讀之以當裘；孤寂而讀之，以當友朋；幽憂而讀之，\n以當金石琴瑟也。」這句話的涵義，與下列何者最接近？", "options": ["讀書百遍義自現，尋根求源探其妙", "處逆何妨將書讀，興味來時百憂除", "紙上得來終覺淺，方知此事要躬行", "求學當如飢索食，問道應似寒需衣"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 23, "raw_text": "23. 「書，飢讀之以當肉；寒讀之以當裘；孤寂而讀之，以當友朋；幽憂而讀之，\n    以當金石琴瑟也。」這句話的涵義，與下列何者最接近？\n    (A)讀書百遍義自現，尋根求源探其妙\n    (B)處逆何妨將書讀，興味來時百憂除\n    (C)紙上得來終覺淺，方知此事要躬行\n    (D)求學當如飢索食，問道應似寒需衣\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-024", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "白居易〈題山石榴花〉：「一叢千朵壓闌干，剪碎紅綃卻作團。風嫋舞腰香不盡，\n露銷妝臉淚新乾。薔薇帶刺攀應懶，菡萏 1 生泥玩亦難。爭及 2 此花檐戶下，任人\n採弄盡人看。」下列關於這首詩的說明，何者錯誤？\n", "options": ["「剪碎紅綃卻作團」――描寫山石榴花的形態     1.菡萏：荷花的別名", "「露銷妝臉淚新乾」――描寫賞花人心緒神態     2.爭及：哪裡比得上", "「薔薇帶刺攀應懶」――意指薔薇有刺，使人懶於採摘", "「菡萏生泥玩亦難」――意指荷花長於淤泥，不易親近"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 24, "raw_text": "24. 白居易〈題山石榴花〉：「一叢千朵壓闌干，剪碎紅綃卻作團。風嫋舞腰香不盡，\n    露銷妝臉淚新乾。薔薇帶刺攀應懶，菡萏 1 生泥玩亦難。爭及 2 此花檐戶下，任人\n    採弄盡人看。」下列關於這首詩的說明，何者錯誤？\n                                \n    (A)「剪碎紅綃卻作團」――描寫山石榴花的形態     1.菡萏：荷花的別名\n    (B)「露銷妝臉淚新乾」――描寫賞花人心緒神態     2.爭及：哪裡比得上\n    (C)「薔薇帶刺攀應懶」――意指薔薇有刺，使人懶於採摘\n    (D)「菡萏生泥玩亦難」――意指荷花長於淤泥，不易親近\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-025", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「如果有人認為文學是不著塵色的白裳，那是因為他遺忘了『現實』這一件緇衣。\n崇拜詩聖杜甫的人，不見得讀得懂『杜詩』，但我們不難想像，當杜甫自外訪\n友歸來，一進門問他老妻第一句話，也許是：『尚有油鹽否？』」根據文意，\n下列何者最符合本文作者的看法？", "options": ["偉大的詩人也須面對生活中的問題", "超脫世俗觀點的文學作品最為動人", "物質生活的滿足與文學創作難以兼顧", "杜詩的可貴之處在於以生活瑣事入詩"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 25, "raw_text": "25. 「如果有人認為文學是不著塵色的白裳，那是因為他遺忘了『現實』這一件緇衣。\n    崇拜詩聖杜甫的人，不見得讀得懂『杜詩』，但我們不難想像，當杜甫自外訪\n    友歸來，一進門問他老妻第一句話，也許是：『尚有油鹽否？』」根據文意，\n    下列何者最符合本文作者的看法？\n    (A)偉大的詩人也須面對生活中的問題\n    (B)超脫世俗觀點的文學作品最為動人\n    (C)物質生活的滿足與文學創作難以兼顧\n    (D)杜詩的可貴之處在於以生活瑣事入詩\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-026", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的字詞，何者意義前後相同？", "options": ["「曾」不吝情去留／「曾」益其所不能", "「安」能辨我是雄雌／爾「安」敢輕吾射", "「行」拂亂其所為／月色入戶，欣然起「行」", "「當」窗理雲鬢／使安期有此性，猶「當」無一豪可論"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 26, "raw_text": "26. 下列文句「」中的字詞，何者意義前後相同？\n    (A)「曾」不吝情去留／「曾」益其所不能\n    (B)「安」能辨我是雄雌／爾「安」敢輕吾射\n    (C)「行」拂亂其所為／月色入戶，欣然起「行」\n    (D)「當」窗理雲鬢／使安期有此性，猶「當」無一豪可論\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-027", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "「余猶及見老儒先生，自言其少時，欲求《史記》、《漢書》而不可得，幸而得\n之，皆手自書，日夜誦讀，惟恐不及。近歲市人轉相摹刻諸子百家之書，日傳萬\n紙，學者之於書，多且易致如此，其文詞學術，當倍蓰 1 於昔人，而後生科舉之\n士皆束書不觀，游談無根，此又何也？」下列敘述何者最符合這段文字的意旨？", "options": ["喜見印刷術進步，學術創作大量增加 ", "讚許後生可畏，高談闊論，縱橫無礙     1.蓰：音ㄒㄧˇ，五倍", "自傷書本取得不易，學識難與後輩抗衡", "感嘆讀書風氣日下，與書籍出版量不成正比"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 27, "raw_text": "27. 「余猶及見老儒先生，自言其少時，欲求《史記》、《漢書》而不可得，幸而得\n    之，皆手自書，日夜誦讀，惟恐不及。近歲市人轉相摹刻諸子百家之書，日傳萬\n    紙，學者之於書，多且易致如此，其文詞學術，當倍蓰 1 於昔人，而後生科舉之\n    士皆束書不觀，游談無根，此又何也？」下列敘述何者最符合這段文字的意旨？\n    (A)喜見印刷術進步，學術創作大量增加\n                            \n    (B)讚許後生可畏，高談闊論，縱橫無礙     1.蓰：音ㄒㄧˇ，五倍\n    (C)自傷書本取得不易，學識難與後輩抗衡\n    (D)感嘆讀書風氣日下，與書籍出版量不成正比\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-104-chinese-028", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-104-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的成語，何者使用最恰當？", "options": ["他為人作惡多端，今日落得如此下場，真是「甕中捉鱉」", "多年之後重回故鄉，不禁有「移山倒海」、世事多變之嘆", "他對流浪動物毫不關心，視之如「白雲蒼狗」，不屑一顧", "這家臺菜館味美價廉，難怪客人絡繹不絕、「戶限為穿」"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "d8389a61e98a", "answer_pdf_sha1": "c729af5ae186", "flags": [], "parse_confidence": 1.0, "original_question_number": 28, "raw_text": "28. 下列文句「」中的成語，何者使用最恰當？\n    (A)他為人作惡多端，今日落得如此下場，真是「甕中捉鱉」\n    (B)多年之後重回故鄉，不禁有「移山倒海」、世事多變之嘆\n    (C)他對流浪動物毫不關心，視之如「白雲蒼狗」，不屑一顧\n    (D)這家臺菜館味美價廉，難怪客人絡繹不絕、「戶限為穿」\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
